// Extractor de datos de contratos de arrendamiento colombianos
const texto = $input.first().json.body.texto || '';

// Función auxiliar para limpiar texto
const limpiarTexto = (str) => str ? str.trim().replace(/\s+/g, ' ') : null;

// Función para extraer números de documentos
const extraerNumero = (str) => str ? str.replace(/[^0-9]/g, '') : null;

// Función para parsear valores monetarios colombianos
const parsearMoneda = (str) => {
  if (!str) return null;
  // Remover símbolo de peso, puntos de miles y convertir coma decimal
  const limpio = str.replace(/[$\s]/g, '').replace(/\./g, '').replace(',', '.');
  return parseFloat(limpio) || null;
};

// ==================== EXTRACCIÓN DE ARRENDADOR ====================
let arrendadorNombre = null;
let arrendadorDocumento = null;
let arrendadorTipoDoc = null;

// Patrón para ARRENDADOR con nombre y documento
const patronArrendador = /ARRENDADOR[:\s]*([A-ZÁÉÍÓÚÑ][A-Za-záéíóúñ\s]+?)(?:,?\s*(?:identificad[oa]\s*con|con)?\s*)?(NIT|C\.?C\.?|C[ée]dula)[.:\s]*([\d.,\-]+)/i;
const matchArrendador = texto.match(patronArrendador);

if (matchArrendador) {
  arrendadorNombre = limpiarTexto(matchArrendador[1]);
  arrendadorTipoDoc = matchArrendador[2].toUpperCase().includes('NIT') ? 'NIT' : 'C.C.';
  arrendadorDocumento = extraerNumero(matchArrendador[3]);
} else {
  // Intento alternativo: buscar NIT o CC después de mencionar arrendador
  const patronArrendadorAlt = /ARRENDADOR[:\s]*([^,\n]+)/i;
  const matchAlt = texto.match(patronArrendadorAlt);
  if (matchAlt) arrendadorNombre = limpiarTexto(matchAlt[1]);

  // Buscar NIT cerca del contexto de arrendador
  const patronNIT = /NIT[.:\s]*([\d.,\-]+)/i;
  const matchNIT = texto.match(patronNIT);
  if (matchNIT) {
    arrendadorDocumento = extraerNumero(matchNIT[1]);
    arrendadorTipoDoc = 'NIT';
  }
}

// ==================== EXTRACCIÓN DE ARRENDATARIO ====================
let arrendatarioNombre = null;
let arrendatarioDocumento = null;
let arrendatarioTipoDoc = 'C.C.';

// Patrón para ARRENDATARIO
const patronArrendatario = /ARRENDATARIO[:\s]*([A-ZÁÉÍÓÚÑ][A-Za-záéíóúñ\s]+?)(?:,?\s*(?:identificad[oa]\s*con|con)?\s*)?(C\.?C\.?|C[ée]dula)[.:\s]*([\d.,]+)/i;
const matchArrendatario = texto.match(patronArrendatario);

if (matchArrendatario) {
  arrendatarioNombre = limpiarTexto(matchArrendatario[1]);
  arrendatarioDocumento = extraerNumero(matchArrendatario[3]);
} else {
  // Intento alternativo
  const patronArrendatarioAlt = /ARRENDATARIO[:\s]*([^,\n]+)/i;
  const matchAlt2 = texto.match(patronArrendatarioAlt);
  if (matchAlt2) arrendatarioNombre = limpiarTexto(matchAlt2[1]);

  // Buscar CC que no sea del arrendador
  const patronCC = /C\.?C\.?[.:\s]*([\d.,]+)/gi;
  const matchesCC = [...texto.matchAll(patronCC)];
  if (matchesCC.length > 0) {
    // Tomar el primer CC que no sea el del arrendador
    for (const m of matchesCC) {
      const cc = extraerNumero(m[1]);
      if (cc !== arrendadorDocumento) {
        arrendatarioDocumento = cc;
        break;
      }
    }
  }
}

// ==================== EXTRACCIÓN DE CANON ====================
let canonMensual = null;

// Múltiples patrones para canon de arrendamiento
const patronesCanon = [
  /canon\s*(?:de\s*)?(?:arrendamiento)?[^$\d]*\$?\s*([\d.,]+)/i,
  /valor\s*(?:del\s*)?(?:arrendamiento|canon|arriendo)[^$\d]*\$?\s*([\d.,]+)/i,
  /arrendamiento\s*(?:mensual)?[^$\d]*\$?\s*([\d.,]+)/i,
  /suma\s*(?:de)?[^$\d]*\$?\s*([\d.,]+)\s*(?:pesos|mensuales)/i,
  /\$\s*([\d.,]+)\s*(?:pesos)?\s*(?:m\/cte|moneda\s*corriente|mensuales)/i
];

for (const patron of patronesCanon) {
  const matchCanon = texto.match(patron);
  if (matchCanon) {
    canonMensual = parsearMoneda(matchCanon[1]);
    if (canonMensual && canonMensual > 100000) break; // Valor razonable para arriendo
  }
}

// ==================== EXTRACCIÓN DE DIRECCIÓN ====================
let direccionInmueble = null;
let ciudad = null;

// Patrones para dirección
const patronesDireccion = [
  /DIRECCI[ÓO]N[^:]*:[:\s]*([^\n,]+(?:Apto\.?|Apartamento|Casa|Local|Oficina)?[^\n]*)/i,
  /ubicado\s*en[:\s]*([^,\n]+)/i,
  /inmueble\s*(?:ubicado)?\s*(?:en)?[:\s]*([^,\n]+)/i,
  /((?:Calle|Carrera|Avenida|Diagonal|Transversal|Cra\.?|Cl\.?|Av\.?)[^,\n]+)/i
];

for (const patron of patronesDireccion) {
  const matchDir = texto.match(patron);
  if (matchDir) {
    direccionInmueble = limpiarTexto(matchDir[1]);
    break;
  }
}

// Patrones para ciudad
const patronesCiudad = [
  /(?:en\s*la\s*ciudad\s*de|ciudad[:\s]*|ubicado\s*en)\s*([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+(?:\s*D\.?C\.?)?)/i,
  /(Bogot[áa]\s*D\.?C\.?|Medell[íi]n|Cali|Barranquilla|Cartagena|Bucaramanga|Pereira|Santa\s*Marta|C[úu]cuta|Ibagu[ée]|Manizales|Villavicencio)/i
];

for (const patron of patronesCiudad) {
  const matchCiudad = texto.match(patron);
  if (matchCiudad) {
    ciudad = limpiarTexto(matchCiudad[1]);
    break;
  }
}

// ==================== EXTRACCIÓN DE FECHAS Y DURACIÓN ====================
let fechaInicio = null;
let duracionMeses = null;

// Patrones para fecha de inicio
const patronesFecha = [
  /(?:a\s*partir\s*del?|desde\s*el?|inicio[:\s]*|vigencia[:\s]*|comenzar[áa]?\s*el?)\s*(\d{1,2})\s*(?:de)?\s*(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\s*(?:de|del)?\s*(\d{4})/i,
  /(?:fecha\s*de\s*inicio)[:\s]*(\d{1,2})[\/-](\d{1,2})[\/-](\d{4})/i,
  /(\d{1,2})\s*(?:de)?\s*(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\s*(?:de|del)?\s*(\d{4})/i
];

const meses = {
  'enero': '01', 'febrero': '02', 'marzo': '03', 'abril': '04',
  'mayo': '05', 'junio': '06', 'julio': '07', 'agosto': '08',
  'septiembre': '09', 'octubre': '10', 'noviembre': '11', 'diciembre': '12'
};

for (const patron of patronesFecha) {
  const matchFecha = texto.match(patron);
  if (matchFecha) {
    if (meses[matchFecha[2]?.toLowerCase()]) {
      const dia = matchFecha[1].padStart(2, '0');
      const mes = meses[matchFecha[2].toLowerCase()];
      const anio = matchFecha[3];
      fechaInicio = `${anio}-${mes}-${dia}`;
    } else if (matchFecha[1] && matchFecha[2] && matchFecha[3]) {
      fechaInicio = `${matchFecha[3]}-${matchFecha[2].padStart(2, '0')}-${matchFecha[1].padStart(2, '0')}`;
    }
    break;
  }
}

// Patrones para duración
const patronesDuracion = [
  /(?:duraci[óo]n|t[ée]rmino|plazo|vigencia)[^\d]*(\d+)\s*(?:meses?|\(\d+\)\s*meses?)/i,
  /(?:por\s*(?:un\s*)?(?:t[ée]rmino|plazo|periodo)\s*de)\s*(\d+)\s*meses?/i,
  /(\d+)\s*meses?\s*(?:de\s*)?(?:duraci[óo]n|vigencia|plazo)/i,
  /(?:doce|un\s*año)\s*\(?\s*(12)\s*\)?\s*meses?/i
];

for (const patron of patronesDuracion) {
  const matchDuracion = texto.match(patron);
  if (matchDuracion) {
    duracionMeses = parseInt(matchDuracion[1]);
    break;
  }
}

// Si menciona "un año" sin número
if (!duracionMeses && /un\s*a[ñn]o/i.test(texto)) {
  duracionMeses = 12;
}

// ==================== GENERAR ID ÚNICO ====================
const contratoId = 'CTR-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);

// ==================== RESULTADO ====================
return {
  json: {
    contrato_id: contratoId,
    texto_original: texto,
    datos_extraidos: {
      arrendador: {
        nombre: arrendadorNombre,
        documento: arrendadorDocumento,
        tipoDoc: arrendadorTipoDoc
      },
      arrendatario: {
        nombre: arrendatarioNombre,
        documento: arrendatarioDocumento,
        tipoDoc: arrendatarioTipoDoc
      },
      canon_mensual: canonMensual,
      direccion_inmueble: direccionInmueble,
      ciudad: ciudad,
      fecha_inicio: fechaInicio,
      duracion_meses: duracionMeses
    },
    extraccion_exitosa: !!(arrendadorNombre || arrendatarioNombre || canonMensual)
  }
};

// Procesar respuesta de Claude y preparar alertas para guardar
const contratoId = $('Extraer Datos del Contrato').item.json.contrato_id;
const datosExtraidos = $('Extraer Datos del Contrato').item.json.datos_extraidos;
const respuestaClaude = $input.first().json;

// Parsear la respuesta de Claude (puede venir como string o ya parseado)
let analisis;
try {
  if (typeof respuestaClaude.content === 'string') {
    // Limpiar posibles caracteres de markdown
    const textoLimpio = respuestaClaude.content
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();
    analisis = JSON.parse(textoLimpio);
  } else if (respuestaClaude.content && respuestaClaude.content[0]) {
    const texto = respuestaClaude.content[0].text || respuestaClaude.content[0];
    const textoLimpio = texto
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();
    analisis = JSON.parse(textoLimpio);
  } else {
    analisis = respuestaClaude;
  }
} catch (e) {
  // Si falla el parsing, crear estructura por defecto
  analisis = {
    alertas: [{
      tipo: 'info',
      titulo: 'Análisis completado',
      descripcion: 'No se detectaron cláusulas problemáticas evidentes. Se recomienda revisión profesional.',
      referencia_legal: 'Ley 820 de 2003',
      es_clausula_abusiva: false
    }],
    score_riesgo: 10,
    resumen: 'Contrato analizado sin detectar cláusulas claramente abusivas.',
    recomendaciones: ['Consultar con un abogado para revisión detallada']
  };
}

// Preparar alertas para insertar en DB
const alertasParaDB = (analisis.alertas || []).map((alerta, index) => ({
  contrato_id: contratoId,
  tipo: alerta.tipo || 'info',
  titulo: alerta.titulo || 'Alerta sin título',
  descripcion: alerta.descripcion || '',
  referencia_legal: alerta.referencia_legal || '',
  es_clausula_abusiva: alerta.es_clausula_abusiva || false,
  texto_clausula: alerta.texto_clausula || null,
  orden: index
}));

return {
  json: {
    contrato_id: contratoId,
    datos_extraidos: datosExtraidos,
    analisis: analisis,
    alertas_para_db: alertasParaDB,
    score_riesgo: analisis.score_riesgo || 0,
    resumen: analisis.resumen || '',
    recomendaciones: analisis.recomendaciones || []
  }
};

