// Calculadora de incremento de arriendo según IPC (Art. 20 Ley 820)
const input = $input.first().json.body;

// IPC histórico de Colombia (últimos años)
// Fuente: DANE - Estos valores deben actualizarse anualmente
const ipcHistorico = {
  2024: 5.20,  // IPC 2024 (provisional/ejemplo)
  2023: 9.28,  // IPC 2023
  2022: 13.12, // IPC 2022
  2021: 5.62,  // IPC 2021
  2020: 1.61,  // IPC 2020
  2019: 3.80,  // IPC 2019
  2018: 3.18,  // IPC 2018
  2017: 4.09,  // IPC 2017
  2016: 5.75,  // IPC 2016
  2015: 6.77   // IPC 2015
};

const canonActual = parseFloat(input.canon_actual) || 0;
const anioIncremento = parseInt(input.anio) || new Date().getFullYear();
const anioIPC = anioIncremento - 1; // El IPC del año anterior

// Obtener IPC aplicable
let ipcAplicable = ipcHistorico[anioIPC];
let ipcFuente = 'DANE';

if (!ipcAplicable) {
  // Si no tenemos el IPC histórico, usar un valor estimado
  ipcAplicable = 5.0; // Valor estimado conservador
  ipcFuente = 'Estimado (IPC real no disponible)';
}

// Calcular nuevo canon
const incrementoPesos = Math.round(canonActual * (ipcAplicable / 100));
const nuevoCanon = canonActual + incrementoPesos;

// Calcular fecha de aplicación
const fechaContrato = input.fecha_inicio_contrato;
let fechaIncrementoAplicable = null;

if (fechaContrato) {
  const fecha = new Date(fechaContrato);
  fecha.setFullYear(anioIncremento);
  fechaIncrementoAplicable = fecha.toISOString().split('T')[0];
}

// Validaciones adicionales
const alertas = [];

if (input.incremento_propuesto) {
  const incrementoPropuesto = parseFloat(input.incremento_propuesto);
  const porcentajePropuesto = ((incrementoPropuesto - canonActual) / canonActual) * 100;

  if (porcentajePropuesto > ipcAplicable) {
    alertas.push({
      tipo: 'danger',
      mensaje: `El incremento propuesto (${porcentajePropuesto.toFixed(2)}%) excede el IPC permitido (${ipcAplicable}%). Esto es ILEGAL según el Art. 20 de la Ley 820.`,
      diferencia: porcentajePropuesto - ipcAplicable,
      exceso_pesos: incrementoPropuesto - nuevoCanon
    });
  }
}

// Formatear valores para Colombia
const formatearPesos = (valor) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  }).format(valor);
};

return {
  json: {
    success: true,
    calculo: {
      canon_actual: canonActual,
      canon_actual_formateado: formatearPesos(canonActual),
      ipc_aplicable: ipcAplicable,
      ipc_anio: anioIPC,
      ipc_fuente: ipcFuente,
      incremento_maximo_porcentaje: ipcAplicable,
      incremento_maximo_pesos: incrementoPesos,
      incremento_maximo_formateado: formatearPesos(incrementoPesos),
      nuevo_canon_maximo: nuevoCanon,
      nuevo_canon_formateado: formatearPesos(nuevoCanon),
      fecha_aplicacion: fechaIncrementoAplicable
    },
    base_legal: {
      articulo: 'Artículo 20',
      ley: 'Ley 820 de 2003',
      texto: 'El precio mensual del arrendamiento no podrá exceder el uno por ciento (1%) del valor comercial del inmueble, o de la parte de él que se dé en arriendo. El arrendamiento fijado en el contrato se reajustará cada doce (12) meses de ejecución del contrato, en una proporción que no sea superior al ciento por ciento (100%) del incremento que haya tenido el índice de precios al consumidor en el año calendario inmediatamente anterior.'
    },
    alertas: alertas,
    timestamp: new Date().toISOString()
  }
};
